mapper.insert:

/* pcy.study.server.domain.User.insertUser */
    INSERT INTO user ( userId
                     , password
                     , nickname
                     , isWithDraw
                     , isAdmin
                     , createdAt)
    VALUES ( #{userId}
           , #{password}
           , #{nickname}
           , #{isWithDraw}
           , #{isAdmin}
           , NOW())

mapper.select:

/* pcy.study.server.domain.User.existUserId */
    SELECT IF(COUNT(*) > 0, 1, 0)
    FROM user
    WHERE userId = #{userId}

mapper.update:

/* pcy.study.server.domain.User.updateUser */
    UPDATE user
    SET password = #{password},
        nickname = #{nickname},
        isWithDraw = #{isWithDraw},
        isAdmin = #{isAdmin}
    WHERE id = #{id}

mapper.delete:

/* pcy.study.server.domain.User.deleteUser */
    DELETE
    FROM user
    WHERE id = #{id}
